ee:message.ee:set-payload:
%dw 2.0
output application/json

//Assign pagination fields to local variables for cleaner math
var current = payload.pagination.currentPage
var perPage = payload.pagination.itemsPerPage
var totalItems = payload.pagination.totalItems

//Math ceiling implementation using DataWeave's ceil function
var totalPages = ceil(totalItems / perPage)
---
{
	"syncStatus": "SUCCESS",
	"navigation": {
		"activePage": current,
		"totalPages": totalPages,
		"hasMorePages": current < totalPages
	},
	//Normalizing and transforming the nested array elements
	"products": payload.records map (item) -> {
		"partNumber": item.sku,
		"displayName": item.details.name,
		"supplierCost": item.details.cost,
		//Applying 15% VAT and rounding down to the nearest integer
		"retailPriceLKR": round(item.details.cost * 1.15)
	}
}
